code = """import json
import re

# Get all business data
business_data = locals()['var_functions.query_db:2']

# Function to extract state from description
def extract_state(description):
    if not description:
        return None
    
    # Look for patterns like "in [City], [State]" or ", [State]"
    patterns = [
        r'[,.]\s*([A-Z]{2})[,\s]',  # Pattern: , XX or . XX
        r'in\s+[^,]+[,\s]+([A-Z]{2})',  # Pattern: in City, XX
        r'\n([A-Z]{2})[\s,]',  # Pattern: newline then XX
    ]
    
    for pattern in patterns:
        match = re.search(pattern, description)
        if match:
            return match.group(1)
    
    return None

# Extract state and aggregate review counts per state
state_reviews = {}
state_businesses = {}

for business in business_data:
    desc = business.get('description', '')
    review_count = int(business.get('review_count', 0))
    business_id = business.get('business_id', '')
    
    state = extract_state(desc)
    
    if state:
        state_reviews[state] = state_reviews.get(state, 0) + review_count
        if state not in state_businesses:
            state_businesses[state] = []
        state_businesses[state].append({
            'business_id': business_id,
            'review_count': review_count,
            'name': business.get('name')
        })

# Find state with highest number of reviews
top_state = max(state_reviews.items(), key=lambda x: x[1]) if state_reviews else None

print('__RESULT__:')
print(json.dumps({
    'total_businesses': len(business_data),
    'states_with_reviews': len(state_reviews),
    'review_counts_by_state': state_reviews,
    'top_state': {
        'state': top_state[0],
        'total_reviews': top_state[1],
        'business_count': len(state_businesses[top_state[0]])
    } if top_state else None,
    'all_states': list(state_reviews.keys())
}, indent=2))"""

